import request from '@/utils/request'

// 档案数据管理
const profile = {
  // 获取完整档案数据
  getData() {
    console.log('获取完整档案数据')
    return request.get('/api/v1/users/profile/data/')
  },

  // 获取简历完整度
  getCompleteness() {
    console.log('获取简历完整度')
    return request.get('/api/v1/users/profile/completeness/')
  },

  // 更新完整档案数据
  updateData(data) {
    console.log('更新完整档案数据:', data)
    return request({
      url: '/api/v1/users/profile/data/',
      method: 'put',
      data
    })
  },

  // 更新模块数据
  updateModule(type, data) {
    // 针对不同类型的模块使用不同的 endpoint
    switch (type) {
      case 'basic_info':
        return request.put('/users/profile/basic-info/', data)
      case 'job_intention':
        return request.put('/users/profile/job-intention/', data)
      case 'work_experience':
        // 工作经历需要使用 ID 进行更新
        return request.put(`/users/profile/work-experiences/${data.id}/`, data)
      default:
        return request.put(`/users/profile/${type}/`, data)
    }
  },

  // 添加模块项
  addModuleItem(type, data) {
    switch (type) {
      case 'work_experience':
        return request.post('/users/profile/work-experiences/', data)
      default:
        return request.post(`/users/profile/${type}/`, data)
    }
  },

  // 删除模块项
  deleteModuleItem(type, id) {
    switch (type) {
      case 'work_experience':
        return request.delete(`/users/profile/work-experiences/${id}/`)
      default:
        return request.delete(`/users/profile/${type}/${id}/`)
    }
  },

  // 上传头像
  uploadAvatar(formData) {
    console.log('上传头像')
    return request({
      url: '/api/v1/users/profile/avatar/upload/',
      method: 'post',
      headers: {
        'Content-Type': 'multipart/form-data'
      },
      data: formData
    })
  },

  // 获取布局配置
  getLayout() {
    console.log('获取布局配置')
    return request.get('/api/v1/users/profile/layout/')
      .then(response => {
        console.log('布局配置响应:', response.data)
        return response
      })
  },

  // 更新布局配置
  updateLayout(data) {
    console.log('更新布局配置:', data)
    console.log('布局数据结构:', JSON.stringify(data, null, 2))
    return request({
      url: '/api/v1/users/profile/layout/',
      method: 'put',
      data
    })
  }
}

export default profile
